cd "G:/Cocos_Project/uk_872_eyestrike2_client" && node -e '
const fs=require("fs");
const data=JSON.parse(fs.readFileSync("assets/game/Prefab/BuyBonus/BuyBonusWindow.prefab","utf8"));
function compName(t){return t? t.replace(/^cc\./,""):t;}
// 找出 root node id (Prefab.data)
const prefab=data.find(o=>o.__type__==="cc.Prefab");
const rootId=prefab.data.__id__;
function nodeComps(node){
  const names=(node._components||[]).map(c=>{const comp=data[c.__id__];return compName(comp&&comp.__type__);}).filter(Boolean);
  return names;
}
function walk(id,depth){
  const node=data[id];
  if(!node||node.__type__!=="cc.Node")return;
  const comps=nodeComps(node);
  const active=node._active===false?" [inactive]":"";
  const cstr=comps.length?"  <"+comps.join(", ")+">":"";
  console.log("  ".repeat(depth)+"- "+node._name+active+cstr);
  (node._children||[]).forEach(ch=>walk(ch.__id__,depth+1));
}
walk(rootId,0);
'
